#!/usr/bin/env node

import { execSync } from 'node:child_process';

import { getRegistryNamespace } from './artifactory.mjs';

function checkArtifactoryPassword(registry) {
  const passwordKey = `${registry}:_password`;

  try {
    // Check npm config list for the artifactory password (protected options show as [hidden])
    const result = execSync('npm config list', {
      encoding: 'utf8',
      stdio: 'pipe',
    });

    // Look for the artifactory password configuration
    if (!result.includes(passwordKey)) {
      throw new Error('Artifactory password not configured');
    }
  } catch (error) {
    console.error('\n❌ ERROR: Artifactory credentials are not set.');
    console.error(
      'Refer to the readme for instructions on setting up Artifactory.\n'
    );
    process.exit(1);
  }
}

function unsetLocalArtifactoryToken(registry) {
  try {
    execSync(`npm config delete ${registry}:_authToken`, {
      stdio: 'inherit',
    });
  } catch (error) {
    console.error('Error unsetting npm config:', error.message);
    process.exit(1);
  }
}

function main() {
  const registry = getRegistryNamespace();
  checkArtifactoryPassword(registry);
  unsetLocalArtifactoryToken(registry);
}

main();
